var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"오늘 새벽, 한 무리의 괴한이 다국적 군사 연구소를 습격한 사건이 벌어져 사회에 충격을 줬습니다.","JPN":"本日の明け方、身元不明の侵入者によって、\\n多国籍軍事研究所が襲撃される事件が発生しました。","ENG":"Early this morning, a group of armed suspects brazenly raided a multinational military research center.","TWN":"今天淩晨，一群恐怖分子襲擊了多國軍事研究所，該事件對整個社會造成了很大的衝擊。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"현장의 기자 연결해 보겠습니다.","JPN":"現場の記者からです。","ENG":"Let's hear from our reporter on site.","TWN":"我們把鏡頭交給位在現場的記者。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"지금 보고 계시는 곳은 습격을 받은 퓨처 앳 워 산하 군사기술 연구소입니다.","JPN":"こちらは、襲撃を受けたフューチャーアットウォー傘下の軍事技術研究所です。","ENG":"The military research facility attacked this morning belongs to an organization called Future at War.","TWN":"我們現在看到的是遭受襲擊的天啟兵器軍事技術研究所。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_UI_RECRUITMNET_HELICOPTER_LOOP"},{"id":"L6_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"보안 인력이 있었지만, 중화기를 앞세운 괴한들을 막기에는 역부족이었습니다.","JPN":"警備員がいましたが、重火器を持っていた侵入者を防ぐことはできませんでした。","ENG":"Although the facility had security personnel, they were unable to fend off the attackers, who used heavy weaponry.","TWN":"據我們瞭解，雖然當時現場有保全人員，但他們無法阻擋配備了重武器的恐怖分子。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"현지 시각 새벽 2시, 보안 설비를 차단하고 연구소에 침입한 괴한들은 보안 직원 7명을 살해한 뒤 연구소 전산실에 침입했습니다.","JPN":"現地時間で午前2時、セキュリティ設備を遮断して研究所に侵入した者たちは、\\n警備員7人を殺害し、研究所の電算室に入り込みました。","ENG":"At approximately 2 a.m., the assailants shut down the security system and infiltrated the facility. They murdered seven security guards before slipping into the main computing center here.","TWN":"當地時間淩晨2點，入侵的恐怖分子關閉安保系統後，殺害了7名職員，隨後進入研究所的電腦室。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"이들은 연구소에서 보관 중이던 기밀자료를 모처에 전송한 것으로 추정됩니다.","JPN":"彼らは研究所に保管されていた機密資料を、某所へ転送したと思われます。","ENG":"They appear to have downloaded top secret data kept at this facility and transmitted it to an unknown recipient.","TWN":"警方推測，恐怖分子的目的是將保管在研究所內的機密資料發送到某處。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"침입자들은 신고를 받고 출동한 경찰과의 교전 끝에 도주한 것으로 알려졌습니다.","JPN":"侵入者たちは通報を受けて出動した警察との交戦の末、逃走した模様です。","ENG":"The attackers fled the scene after a firefight with the police who responded to the 911 call.","TWN":"報告顯示，恐怖分子在與收到通報的員警交火後逃逸。"},"stage":{"bg":"CITY_TWILIGHT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TV3_NPC_NULL_NULL","text":{"KOREA":"한밤중에 난리도 아니었어요.","JPN":"真夜中に大騒ぎをしていました。","ENG":"It got all crazy in the middle of the night.","TWN":"大半夜鬧得可厲害了。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L13_1","type":"dialog","speaker":"TV3_NPC_NULL_NULL","text":{"KOREA":"대로 쪽에서 총소리에 뭐가 크게 터지는 소리까지 들렸는데, 무서워서 무슨 일인가 보지도 못하고......","JPN":"道路の方から銃声や爆弾音が聞こえたんですけど、\\n怖くて何が起きてるのか、確認することもできませんでした……","ENG":"I could hear guns firing and stuff exploding from the road, but I was too scared to see what it was about...","TWN":"路那邊傳來了槍聲和爆炸聲，但是我太害怕了不敢看……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L15_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"현지 경찰은 사건 자료를 관리국에 전달하고 결과가 나오기만을 기다린다는 입장을 내놓았습니다.","JPN":"現地の警察は、事件資料を管理局へ受け渡し、結果を待ってます。","ENG":"The local police submitted their findings to the Administration, and have not commented beyond saying they are awaiting the results of the investigation.","TWN":"當地警方宣佈將把案件資料轉交給管理局，等待調查結果。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"이렇듯 경찰 측이 신중한 입장을 취하는 반면, 연구소 측은 이번 사건의 모 정부가 배후에 있다고 발언했습니다.","JPN":"警察が事件に対して慎重に対応している一方、研究所は今回の件に某政府が関わっていると発言しました。","ENG":"While the police remain quiet, the research center says a certain nation's government may have masterminded this incident.","TWN":"與採取慎重立場的警方相反，研究所方面則表示這次事件背後有政府參與。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"이에 대해 국제 정치 평론가 분을 모시고 자세한 이야기를 나눠 보도록 하겠습니다.","JPN":"これについて、国際政治評論家の方から詳しい話を伺います。","ENG":"We have with us in the studio an expert on international politics to discuss this in further detail.","TWN":"我們邀請了國際政治評論家對此進行詳細討論。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"안녕하십니까, 교수님.","JPN":"よろしくお願いします、教授。","ENG":"Hello, professor.","TWN":"您好，教授。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"안녕하세요.","JPN":"よろしくお願いします。","ENG":"Hello.","TWN":"您好。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"이번 사건 뒤에 정치적인 갈등이 숨어 있다고 논평해 주셨는데, 어떤 이유에서입니까?","JPN":"今回の事件には政治的な葛藤が隠されているとおっしゃっていましたが、\\nその理由を説明していただけますか？","ENG":"You've noted that there are hidden political motivations behind this incident. What makes you say that?","TWN":"您說這個事件背後存在政治糾紛，請問您這麼評價的原因是什麼？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"퓨처 앳 워는 대 침식전에 필요한 여러 기술을 개발, 공유해 온 다국적 기관입니다.","JPN":"フューチャーアットウォーは、対侵食戦に必要な様々な技術を開発し、共有していた多国籍機関です。","ENG":"Future at War is a multinational organization that has been developing and shares many technologies required for our fight against Corruption from the Counterside.","TWN":"天啟兵器是為了對抗侵蝕體而開發、共用多種技術的跨國機構。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"관리국이 공개한 기술을 지금까지 가장 많이 재현해 낸 곳이죠.","JPN":"管理局が公開した技術を、今までもっとも多く再現した機関でもあります。","ENG":"It has been a leader in duplicating the technologies disclosed by the Administration thus far.","TWN":"這裡最大程度地再現了管理局公開的技術。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"문제는 병기를 증여해도 핵심 기술은 엄중히 관리하는데, 각국은 이 기술들이 향후 국방력 경쟁에 큰 영향을 끼칠 것으로 보고 있습니다.","JPN":"この機関は、兵器を渡すことがあってもコア技術は厳重に管理しています。\\n各国はこの技術が今後、防衛力競争に大きな影響を及ぼすと考えてます。","ENG":"The problem is, even if they share the weapon systems produced from their R&D, they are very wary of disclosing the core technology. The countries involved are concerned such technologies will lead to a new arms race.","TWN":"問題是就算他們提供了武器，武器的核心技術還是會受到嚴格管理。因此各國都認為，這些技術將對未來的國防競爭產生巨大的影響。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"단적인 예가 타이탄입니다.","JPN":"その代表的な例がタイタンです。","ENG":"For example, there is the Titan.","TWN":"最明顯的例子就是泰坦。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"대정화 전쟁 후반기에나, 그것도 시험기만 급히 투입되었는데도 카운터를 제외하면 독보적인 전과를 올렸죠.","JPN":"大浄化戦争の後半に、テスト機を緊急出撃させただけで、カウンターを除いた中で圧倒的な戦果を記録しています。","ENG":"Although only a prototype was deployed late in the Grand Purification War, it proved to be remarkably capable, rivaled only by the Counters themselves.","TWN":"淨化之戰後期，泰坦雖然未經實戰便緊急投入了戰場，卻還是獲得了僅次於制裁者的戰果。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"타이탄이라면 저도 들어본 적 있습니다. 그런 걸 각국이 자체적으로 개발하긴 어려운가요?","JPN":"タイタンなら私も聞いたことがあります。それを各国が開発することは難しいのでしょうか？","ENG":"I think I've heard of this Titan weapon. Is it difficult for each country to independently develop a system like that?","TWN":"我也聽說過泰坦。各國要自主研發這些武器很困難嗎？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"20년쯤 지나면 어려운지 불가능한지는 알 수 있겠죠.","JPN":"20年後には、難しいのか不可能なのか、判断できるでしょう。","ENG":"In about 20 years, we'll find out if it's just difficult or absolutely impossible.","TWN":"在20年內是不可能的。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"어쨌거나, 국제 사회도 결국은 힘의 논리에 따라 돌아갑니다. 하루가 급한 전시라면 모를까, 지금은 누구나 눈독을 들이게 된 거죠.","JPN":"いずれにせよ、国際社会も結局は力によって支配されます。\\n戦時中ならともかく、現在は誰もがその技術を狙っているのです。","ENG":"In any case, international relations are decided according to the theory of power. Now that the urgency of the war is over, every country wants to claim this capability for their own.","TWN":"不管怎樣，國際社會最終還是會遵循弱肉強食的原則。如果只是一天的緊急展覽那就算了，但現在所有人都在密切關注這件事吧。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"이번에 탈취된 자료는 타이탄에 탑재된 전열화학 평사포의 설계도라고 합니다. 직격하면 제 3종 침식체도 치명상을 입는 병기죠.","JPN":"今回盗まれた資料は、タイタンに搭載された電熱化学平射砲の設計図だそうです。\\n直撃すれば、第3種侵食体にも致命傷を与える兵器です。","ENG":"It's been reported that the data stolen from the lab is the blueprint for the electrothermal chemical gun equipped on the Titan. A direct hit from the ETCG is enough to critically wound even a Category 3 C.O.","TWN":"這次被搶奪的是泰坦上所搭載的電熱化學炮設計圖。是一個直接命中，就可以對3級侵蝕體造成致命傷害的兵器。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"따라서 이번 사태는 사건이 벌어진 연구소가 있는 국가와 적대 관계인 나라의 소행일 가능성이 높습니다.","JPN":"よって、この事件は研究所がある国と、敵対関係にある国の仕業だと思われます。","ENG":"As such, it is highly likely that this incident was masterminded by an adversary of one or multiple member states in the research consortium.","TWN":"因此這次事件很可能是研究院所屬國的敵國所為。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"다른 국가들도 자극을 받을 텐데, 이번 한 번으로 끝나길 바라야겠군요.","JPN":"他の国も同じようなことを考えるかもしれません。厳重な注意が必要ですね。","ENG":"This will probably have the other countries shifting in their chairs... I just hope this will turn out to be an isolated case.","TWN":"其他各國也有可能受到此次事件的刺激，希望這件事能夠就此結束。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"그렇다면 교수님이 보시기엔 어떤 국가의 소행일까요? 만약 내막이 밝혀지면 외교적인 분쟁으로까지 비화되지 않겠습니까?","JPN":"では、教授。どの国が今回の事件を起こしたと予想されますか？\\nもし、詳しい事情が明らかになれば、外交的な紛争に発展しかねないと思われるのですが？","ENG":"Which country do you think could be after this then? If we find out who's responsible, couldn't it escalate to an international incident?","TWN":"那麼教授您認為會是哪個國家的所為呢？如果內幕被揭露出來，會不會引發外交爭端？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TV4_NPC_NULL_NULL","text":{"KOREA":"물론입니다. 하지만 현지 정세를 고려하면, 이 사건을 빌미로 정부를 압박해 경제적인 이득을 취하는 데 그칠 전망이.......","JPN":"もちろんです。しかし現地の情勢を踏まえると、この事件で政府を圧迫して、経済的な利益を得る程度に過ぎないと……","ENG":"Of course. But considering the current situation, it may end with measures such as diplomatic pressure to gain economic advantages instead...","TWN":"當然。但是考慮到當地的形勢，以此次事件為藉口對政府施加壓力，從而獲得經濟上的利益……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};